class Solution {
public:
    void merge(vector<int>& nums1, int m, vector<int>& nums2, int n) {
        int num1p = m -1;
        int num2p = n -1;
        int point = n + m -1;

        while (num1p >= 0 && num2p >= 0){
            if (nums1[num1p] > nums2[num2p]){
                nums1[point] = nums1[num1p];
                num1p--;
            } else{
                nums1[point] = nums2[num2p];
                num2p--;
            }
            point--;
        }

        while(num2p >= 0){
            nums1[point] = nums2[num2p];
            num2p--;
            point--;
        }

    }
};
